class Solution:
    def getMaxRepetitions(self, s1: str, n1: int, s2: str, n2: int) -> int:
        if n1 == 0:
            return 0
        s1_len, s2_len = len(s1), len(s2)
        dp = {}
        index, count = 0, 0
        for k in range(1, n1 + 1):
            for ch in s1:
                if ch == s2[index]:
                    index += 1
                    if index == s2_len:
                        count += 1
                        index = 0
            if index in dp:
                prev_k, prev_count = dp[index]
                loop_len = k - prev_k
                loop_count = count - prev_count
                loops = (n1 - prev_k) // loop_len
                count = prev_count + loops * loop_count
                remaining = (n1 - prev_k) % loop_len
                for k2 in range(1, remaining + 1):
                    for ch in s1:
                        if ch == s2[index]:
                            index += 1
                            if index == s2_len:
                                count += 1
                                index = 0
                return count // n2
            dp[index] = (k, count)
        return count // n2
```
efficiency: HIGH
time complexity: O((s1_len + s2_len) * min(n1, s2_len))
space complexity: O(s2_len)
energy implications: LOW
explanation: Uses pattern detection to skip repeated work after finding a cycle in the matching process, reducing the effective iterations from O(n1) to O(s2_len) while keeping memory usage low.

